document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".toggle-password").forEach(r=>{r.addEventListener("click",function(){const t=this.closest(".input-wrapper"),s=t==null?void 0:t.querySelector("input"),o=this.querySelector(".eye-open"),n=this.querySelector(".eye-closed");if(!s)return;const e=s.type==="password";s.type=e?"text":"password",o&&(o.style.display=e?"none":"block"),n&&(n.style.display=e?"block":"none"),this.setAttribute("aria-label",e?"Ocultar contraseña":"Mostrar contraseña")})})});
